module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"쉬운말","note":"쉬운말 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"가이오와 디오드레베","verses":{"krv":[{"n":1,"t":"장로는 사랑하는 가이오 곧 나의 참으로 사랑하는 자에게 편지하노라"},{"n":2,"t":"사랑하는 자여 네 영혼이 잘됨 같이 네가 범사에 잘되고 강건하기를 내가 간구하노라"},{"n":3,"t":"형제들이 와서 네게 있는 진리를 증거하되 네가 진리 안에서 행한다 하니 내가 심히 기뻐하노라"},{"n":4,"t":"내가 내 자녀들이 진리 안에서 행한다 함을 듣는 것보다 더 즐거움이 없도다"},{"n":5,"t":"사랑하는 자여 네가 무엇이든지 형제 곧 나그네 된 자들에게 행하는 것이 신실한 일이니"},{"n":6,"t":"저희가 교회 앞에서 너의 사랑을 증거하였느니라 네가 하나님께 합당하게 저희를 전송하면 가하리로다"},{"n":7,"t":"이는 저희가 주의 이름을 위하여 나가서 이방인에게 아무 것도 받지 아니함이라"},{"n":8,"t":"이러므로 우리가 이같은 자들을 영접하는 것이 마땅하니 이는 우리로 진리를 위하여 함께 수고하는 자가 되게 하려 함이니라"},{"n":9,"t":"내가 두어 자를 교회에게 썼으나 저희 중에 으뜸되기를 좋아하는 디오드레베가 우리를 접대하지 아니하니"},{"n":10,"t":"이러므로 내가 가면 그 행한 일을 잊지 아니하리라 저가 악한 말로 우리를 망령되이 폄론하고도 유위부족하여 형제들을 접대치도 아니하고 접대하고자 하는 자를 금하여 교회에서 내어 쫓는도다"},{"n":11,"t":"사랑하는 자여 악한 것을 본받지 말고 선한 것을 본받으라 선을 행하는 자는 하나님께 속하고 악을 행하는 자는 하나님을 뵈옵지 못하였느니라"},{"n":12,"t":"데메드리오는 뭇사람에게도, 진리에게도 증거를 받았으매 우리도 증거하노니 너는 우리의 증거가 참된 줄을 아느니라"},{"n":13,"t":"내가 네게 쓸 것이 많으나 먹과 붓으로 쓰기를 원치 아니하고"},{"n":14,"t":"속히 보기를 바라노니 또한 우리가 면대하여 말하리라"},{"n":15,"t":"평강이 네게 있을지어다 여러 친구가 네게 문안하느니라 너는 각 친구 명하에 문안하라"}],"kids":[{"n":1,"t":"장로(인 나)가 사랑하는 가이오, 곧 내가 진심으로 사랑하는 사람에게 편지를 써요."},{"n":2,"t":"사랑하는 형제여, 그대의 영혼이 잘되는 것처럼, 그대가 모든 일에서 잘되고 건강하기를 내가 기도해요."},{"n":3,"t":"형제들이 와서 그대에게 있는 진리를 증언했고, 또 그대가 진리 안에서 살아가고 있다는 것을 증언했을 때, 나는 매우 기뻤어요."},{"n":4,"t":"내 자녀들이 진리 안에서 살아간다는 소식을 듣는 것보다 더 큰 기쁨이 내게는 없어요."},{"n":5,"t":"사랑하는 형제여, 그대가 형제들, 곧 나그네로 와 있는 사람들에게 무엇이든지 행하는 그 일은 신실한 일이에요."},{"n":6,"t":"그들이 교회 앞에서 그대의 사랑에 대해 증언했어요. 그대가 하나님께 합당한 방식으로 그들을 잘 보내 준다면 좋겠어요."},{"n":7,"t":"이는 그들이 그분(예수님)의 이름을 위해 나가서, 이방 사람들에게서 아무것도 받지 않기 때문이에요."},{"n":8,"t":"그러므로 우리가 이런 사람들을 영접하는 것이 마땅해요. 이렇게 해야 우리도 진리를 위해 함께 일하는 사람이 되니까요."},{"n":9,"t":"내가 교회에 짧은 글을 써 보냈는데, 그들 가운데 으뜸이 되기를 좋아하는 디오드레베가 우리를 받아 주지 않았어요."},{"n":10,"t":"그러므로 내가 가면, 그가 한 일을 잊지 않고 (드러내) 말할 거예요. 그는 악한 말로 우리를 함부로 헐뜯고 있고, 그것도 모자라서 형제들도 받아 주지 않고, 받아 주려는 사람들조차 막아서 교회에서 쫓아내고 있어요."},{"n":11,"t":"사랑하는 형제여, 악한 것을 본받지 말고 선한 것을 본받으세요. 선을 행하는 사람은 하나님께 속한 사람이고, 악을 행하는 사람은 하나님을 본 적이 없는 사람이에요."},{"n":12,"t":"데메드리오는 모든 사람에게서, 또 진리 자체로부터 증언을 받고 있어요. 우리도 그를 증언해요. 그대는 우리의 증언이 참되다는 것을 알고 있어요."},{"n":13,"t":"내가 그대에게 쓸 것이 많지만, 먹과 붓으로 쓰고 싶지 않아요."},{"n":14,"t":"속히 그대를 만나기를 바라요. 그래서 얼굴을 보고 이야기할게요."},{"n":15,"t":"평강이 그대에게 함께하기를 빌어요. 여러 친구가 그대에게 문안 인사를 보내요. 그대도 그곳의 친구들에게 한 사람 한 사람 이름을 불러서 문안 인사를 전해 주세요."}]}}]}');

